css:
.loader {color: var(--loader-color, #2563eb);
  --loader-secondary-color: #38bdf8;
  --loader-bg: #ffffff;
   width: 70px;
   aspect-ratio: 1;
   background: var(--loader-color, #2563eb);
   clip-path: polygon(100.00% 50.00%,64.14% 64.14%,50.00% 100.00%,35.86% 64.14%,0.00% 50.00%,35.86% 35.86%,50.00% 0.00%,64.14% 35.86%);
   -webkit-mask:radial-gradient(circle 5px,#0000 90%,currentColor);
   animation: l1 1.5s infinite linear;
}
@keyframes l1 {
  100%{transform: rotate(1turn)}
}
